{"code": "import json
import os

# Load Europe articles metadata
europe_file = locals()['var_functions.query_db:5']
with open(europe_file, 'r') as f:
    europe_metadata = json.load(f)

# Group article IDs by year for batch processing
articles_by_year = {}
for article in europe_metadata:
    year = article['publication_date'][:4]  # Extract YYYY from YYYY-MM-DD
    if year not in articles_by_year:
        articles_by_year[year] = []
    articles_by_year[year].append(article['article_id'])

# Calculate total count per year
year_counts = {year: len(ids) for year, ids in articles_by_year.items()}
sorted_years = sorted(year_counts.keys())

print('__RESULT__:')
print(json.dumps({
    'total_articles': len(europe_metadata),
    'year_range': f"{sorted_years[0]}-{sorted_years[-1]}",
    'articles_per_year': year_counts,
    'sample_articles_by_year': {year: articles_by_year[year][:3] for year in sorted_years[:3]}
}))"}

{"code": "import json

# Load Europe metadata to get article IDs
europe_file = locals()['var_functions.query_db:5']
with open(europe_file, 'r') as f:
    europe_metadata = json.load(f)

# Group by year
articles_by_year = {}
for article in europe_metadata:
    year = article['publication_date'][:4]
    if year not in articles_by_year:
        articles_by_year[year] = []
    articles_by_year[year].append(article['article_id'])

# Show years and counts
year_info = {}
for year in sorted(articles_by_year.keys()):
    year_info[year] = len(articles_by_year[year])

print('__RESULT__:')
print(json.dumps({
    'years': sorted(articles_by_year.keys()),
    'year_counts': year_info,
    'total_articles': len(europe_metadata)
}))"}
